// Process trending topics and generate content ideas
const trends = $input.first().json.trends || [];
const contentIdeas = [];

for (const trend of trends.slice(0, 5)) {
  contentIdeas.push({
    topic: trend.topic,
    engagement_score: trend.engagement_score || 0,
    content_type: determineContentType(trend),
    target_platforms: determinePlatforms(trend),
    estimated_time: estimateCreationTime(trend),
    priority: calculatePriority(trend)
  });
}

function determineContentType(trend) {
  if (trend.media_type === 'video') return 'video_script';
  if (trend.word_count > 500) return 'long_form';
  return 'short_form';
}

function determinePlatforms(trend) {
  const platforms = [];
  if (trend.source.includes('twitter')) platforms.push('twitter');
  if (trend.source.includes('reddit')) platforms.push('reddit');
  if (trend.source.includes('news')) platforms.push('linkedin', 'newsletter');
  return platforms.length > 0 ? platforms : ['twitter', 'linkedin'];
}

function estimateCreationTime(trend) {
  const baseTime = 30; // minutes
  const complexity = trend.complexity || 1;
  return baseTime * complexity;
}

function calculatePriority(trend) {
  const engagement = trend.engagement_score || 0;
  const velocity = trend.velocity || 0;
  return (engagement * 0.6 + velocity * 0.4) * 100;
}

return contentIdeas;

// Generate asset creation tasks based on content scripts
const scripts = $input.first().json.scripts || [];
const assetTasks = [];

for (const script of scripts) {
  if (script.content_type === 'video_script') {
    assetTasks.push({
      script_id: script.id,
      asset_type: 'thumbnail',
      requirements: {
        dimensions: '1280x720',
        style: 'engaging',
        include_text: true
      }
    });
    assetTasks.push({
      script_id: script.id,
      asset_type: 'video',
      requirements: {
        duration: '60-90s',
        format: 'mp4',
        include_subtitles: true
      }
    });
  } else {
    assetTasks.push({
      script_id: script.id,
      asset_type: 'featured_image',
      requirements: {
        dimensions: '1200x630',
        style: 'professional'
      }
    });
  }
}

return assetTasks;

// Track publishing results and log performance
const results = $input.all();
const performanceLog = {
  timestamp: new Date().toISOString(),
  total_published: results.length,
  successful: results.filter(r => r.json.success).length,
  failed: results.filter(r => !r.json.success).length,
  platforms: {},
  details: results.map(r => ({
    platform: r.json.platform,
    success: r.json.success,
    content_id: r.json.content_id,
    timestamp: r.json.timestamp
  }))
};

// Group by platform
for (const result of results) {
  const platform = result.json.platform;
  if (!performanceLog.platforms[platform]) {
    performanceLog.platforms[platform] = {
      total: 0,
      successful: 0,
      failed: 0
    };
  }
  performanceLog.platforms[platform].total++;
  if (result.json.success) {
    performanceLog.platforms[platform].successful++;
  } else {
    performanceLog.platforms[platform].failed++;
  }
}

// Send to SIMP broker for logging
const simpPayload = {
  intent_type: 'media_performance_log',
  source_agent: 'n8n_workflow',
  target_agent: 'base_media_agent',
  payload: performanceLog
};

return [
  {
    json: performanceLog,
    pairedItem: {
      item: 0
    }
  },
  {
    json: {
      simp_payload: simpPayload,
      should_send_to_broker: true
    }
  }
];

// Global error handler for the workflow
const errors = $input.all().filter(item => item.json.error);

if (errors.length > 0) {
  const errorSummary = {
    timestamp: new Date().toISOString(),
    total_errors: errors.length,
    errors: errors.map(e => ({
      node: e.json.node_name,
      error: e.json.error,
      timestamp: e.json.timestamp
    }))
  };

  // Send error alert via SIMP broker
  const alertPayload = {
    intent_type: 'media_workflow_error',
    source_agent: 'n8n_workflow',
    target_agent: 'base_media_agent',
    payload: {
      severity: 'high',
      workflow: 'daily_pipeline',
      error_summary: errorSummary
    }
  };

  return {
    json: {
      alert_payload: alertPayload,
      error_summary: errorSummary,
      requires_human_intervention: errors.length > 3
    }
  };
}

return null;
